    local, domain = email.rsplit("@", 1)

    if not local or not domain:
        errors.append("email local part and domain are required")

    if len(local) > 64:
        errors.append("email local part is too long")

    try:
        ascii_domain = domain.encode("idna").decode("ascii")
    except UnicodeError:
        errors.append("email domain is not valid IDN")
        ascii_domain = domain

    normalized = f"{local}@{ascii_domain}"

    if not EMAIL_RE.match(normalized):
        errors.append("email format is invalid")

    if ascii_domain in DISPOSABLE_DOMAINS:
        errors.append("disposable email addresses are not allowed")

    if ascii_domain in {"localhost", "example.com", "example.org", "example.net", "invalid"}:
        errors.append("email domain is not allowed")

    if "." not in ascii_domain:
        errors.append("email domain must be fully qualified")

    return normalized, errors


def has_mx_or_a_record(domain: str) -> bool:
    try:
        dns.resolver.resolve(domain, "MX", lifetime=2)
        return True
    except Exception:
        try:
            dns.resolver.resolve(domain, "A", lifetime=2)
            return True
        except Exception:
            return False


def normalize_username(raw: str) -> tuple[str | None, list[str]]:
    errors = []
    username = normalize_text(raw).lower()

    if not username:
        errors.append("username is required")
        return None, errors

    if len(username) < 3:
        errors.append("username must be at least 3 characters")

    if len(username) > 30:
        errors.append("username must be 30 characters or fewer")

    if username != raw.strip().lower():
        errors.append("username contains unsupported unicode or spacing")

    if not USERNAME_RE.match(username):
        errors.append("username may contain only lowercase letters, numbers, underscore, dot, and hyphen; it must start and end with a letter, number, or underscore")

    if ".." in username or "--" in username or "__" in username:
        errors.append("username must not contain repeated separators")

    if username in RESERVED_USERNAMES:
        errors.append("username is reserved")

    if any(term in username for term in OFFENSIVE_TERMS):
        errors.append("username is not allowed")

    if confusable_or_mixed_script(username):
        errors.append("username contains suspicious mixed-script or confusable characters")

    return username, errors


def confusable_or_mixed_script(value: str) -> bool:
    scripts = set()
    for ch in value:
        if ch.isascii():
            continue
        name = unicodedata.name(ch, "")
        if "CYRILLIC" in name:
            scripts.add("CYRILLIC")
        elif "GREEK" in name:
            scripts.add("GREEK")
        elif "LATIN" in name:
            scripts.add("LATIN")
        else:
            scripts.add("OTHER")
    return bool(scripts)


def normalize_display_name(raw: str) -> tuple[str | None, list[str]]:
    errors = []
    display_name = normalize_text(raw)

    if not display_name:
        errors.append("display_name is required")
        return None, errors

    if len(display_name) < 1:
        errors.append("display_name must not be empty")

    if len(display_name) > 80:
        errors.append("display_name must be 80 characters or fewer")

    if re.search(r"https?://|www\.", display_name, re.IGNORECASE):
        errors.append("display_name must not contain URLs")

    if re.search(r"[<>\"'`]", display_name):
        errors.append("display_name contains unsafe characters")

    if any(term in display_name.lower() for term in OFFENSIVE_TERMS):
        errors.append("display_name is not allowed")

    return escape(display_name, quote=True), errors


def validate_password(password: Any, email: str | None, username: str | None) -> list[str]:
    errors = []

    if not isinstance(password, str):
        return ["password is required"]

    if len(password) > 128:
        errors.append("password must be 128 characters or fewer")

    if len(password) < 12:
        errors.append("password must be at least 12 characters")

    if unicodedata.normalize("NFKC", password) != password:
        errors.append("password contains unsupported unicode normalization forms")

    if any(unicodedata.category(ch)[0] == "C" for ch in password):
        errors.append("password must not contain control characters")

    classes = [
        bool(re.search(r"[a-z]", password)),
        bool(re.search(r"[A-Z]", password)),
        bool(re.search(r"\d", password)),
        bool(re.search(r"[^A-Za-z0-9]", password)),
    ]

    if sum(classes) < 3:
        errors.append("password must include at least three of: lowercase, uppercase, number, symbol")

    lowered = password.lower()

    if lowered in COMMON_PASSWORDS:
        errors.append("password is too common")

    if re.search(r"(.)\1{3,}", password):
        errors.append("password must not contain long repeated characters")

    if re.search(r"(0123|1234|2345|3456|4567|5678|6789|abcd|qwer|asdf)", lowered):
        errors.append("password must not contain obvious sequences")

    if username and username in lowered:
        errors.append("password must not contain username")

    if email:
        local = email.split("@", 1)[0]
        domain = email.split("@", 1)[1].split(".", 1)[0]
        if local and local.lower() in lowered:
            errors.append("password must not contain email local part")
        if domain and domain.lower() in lowered:
            errors.append("password must not contain email domain")

    return errors


async def breached_password(password: str) -> bool:
    sha1 = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()
    prefix, suffix = sha1[:5], sha1[5:]

    try:
        async with httpx.AsyncClient(timeout=3) as client:
            response = await client.get(f"https://api.pwnedpasswords.com/range/{prefix}")
            if response.status_code != 200:
                return False

            for line in response.text.splitlines():
                candidate, _, _count = line.partition(":")
                if hmac.compare_digest(candidate, suffix):
                    return True
    except httpx.HTTPError:
        return False

    return False


def email_fingerprint(email: str) -> str:
    return hmac.new(
        PASSWORD_PEPPER.encode("utf-8"),
        email.encode("utf-8"),
        hashlib.sha256,
    ).hexdigest()


def validate_payload(payload: dict[str, Any]) -> tuple[dict[str, str], dict[str, list[str]]]:
    errors: dict[str, list[str]] = defaultdict(list)
    cleaned: dict[str, str] = {}

    allowed = {"email", "username", "password", "display_name"}
    extra = set(payload) - allowed
    if extra:
        errors["body"].append("unexpected fields are not allowed")

    for field in allowed:
        if field not in payload:
            errors[field].append(f"{field} is required")
        elif not isinstance(payload[field], str):
            errors[field].append(f"{field} must be a string")

    if errors:
        return cleaned, dict(errors)

    email, email_errors = normalize_email(payload["email"])
    username, username_errors = normalize_username(payload["username"])
    display_name, display_name_errors = normalize_display_name(payload["display_name"])

    errors["email"].extend(email_errors)
    errors["username"].extend(username_errors)
    errors["display_name"].extend(display_name_errors)
    errors["password"].extend(validate_password(payload["password"], email, username))

    if email:
        cleaned["email"] = email
    if username:
        cleaned["username"] = username
    if display_name:
        cleaned["display_name"] = display_name

    cleaned["password"] = payload["password"]

    return cleaned, {k: v for k, v in errors.items() if v}


@app.on_event("startup")
def startup() -> None:
    init_db()


@app.post("/api/register")
async def register(request: Request):
    ip = client_ip(request)
    rate_key = f"register:{ip}"

    if rate_limited(rate_key):
        return JSONResponse(
            status_code=429,
            content={
                "ok": False,
                "errors": {
                    "rate_limit": ["too many registration attempts; try again later"]
                },
            },
            headers={"Retry-After": str(RATE_WINDOW_SECONDS)},
        )

    content_length = request.headers.get("content-length")
    if content_length and int(content_length) > MAX_BODY_BYTES:
        return JSONResponse(
            status_code=413,
            content={"ok": False, "errors": {"body": ["request body is too large"]}},
        )

    raw_body = await request.body()
    if len(raw_body) > MAX_BODY_BYTES:
        return JSONResponse(
            status_code=413,
            content={"ok": False, "errors": {"body": ["request body is too large"]}},
        )

    try:
        payload = await request.json()
    except Exception:
        return JSONResponse(
            status_code=400,
            content={"ok": False, "errors": {"body": ["invalid JSON"]}},
        )

    if not isinstance(payload, dict):
        return JSONResponse(
            status_code=422,
            content={"ok": False, "errors": {"body": ["JSON object is required"]}},
        )

    cleaned, errors = validate_payload(payload)

    if cleaned.get("email"):
        domain = cleaned["email"].split("@", 1)[1]
        if not has_mx_or_a_record(domain):
            errors.setdefault("email", []).append("email domain does not accept mail")

    if isinstance(payload.get("password"), str) and await breached_password(payload["password"]):
        errors.setdefault("password", []).append("password appears in known data breaches")

    if errors:
        return JSONResponse(status_code=422, content={"ok": False, "errors": errors})

    try:
        password_material = (cleaned["password"] + PASSWORD_PEPPER).encode("utf-8")
        password_hash = ph.hash(password_material)
    except HashingError:
        return JSONResponse(
            status_code=500,
            content={"ok": False, "errors": {"server": ["could not securely process password"]}},
        )

    now = datetime.now(timezone.utc).isoformat()
    email_hash = email_fingerprint(cleaned["email"])

    try:
        with db() as conn:
            conn.execute(
                """
                INSERT INTO users (
                    email, email_hash, username, display_name, password_hash, created_at
                )
                VALUES (?, ?, ?, ?, ?, ?)
                """,
                (
                    cleaned["email"],
                    email_hash,
                    cleaned["username"],
                    cleaned["display_name"],
                    password_hash,
                    now,
                ),
            )
    except sqlite3.IntegrityError:
        # Do not reveal whether the email or username already exists.
        # Return the same generic response shape used for accepted registration flows.
        time.sleep(secrets.randbelow(150) / 1000)
        return JSONResponse(
            status_code=202,
            content={
                "ok": True,
                "message": "If registration can proceed, verification instructions will be sent.",
            },
        )

    return JSONResponse(
        status_code=201,
        content={
            "ok": True,
            "message": "Registration accepted. Verification instructions will be sent.",
        },
    )
